var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>나오님? 사나에!</color>","JPN":"<color=#ffd34c>ナオ様？　早苗！</color>","ENG":"<color=#ffd34c>Miss Nao? Sanae!</color>","TWN":"<color=#ffd34c>奈緒大人？早苗！</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>들리면 대답해주세요!</color>","JPN":"<color=#ffd34c>聞こえたら返事してください！</color>","ENG":"<color=#ffd34c>Answer if you can hear me!</color>","TWN":"<color=#ffd34c>有聽到我的聲音嗎？回答我！</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"침식파가 강해서 연락이 닿지 않아요.","JPN":"侵食波が強くて連絡が取れません。","ENG":"I cannot reach them. The Corruption ray is too strong.","TWN":"侵蝕波太強聯絡不上。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"괜찮으실 겁니다. 나오님도 함께 계시니까요.","JPN":"大丈夫でしょう。ナオ様もご一緒ですから。","ENG":"I am sure they are all right. Miss Nao is with her.","TWN":"奈緒大人也在，不會有事的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저도 그럴 거라고 생각은 하지만……","JPN":"私もそうだとは思いますが……","ENG":"I hope so too, but...","TWN":"我也是這麼想的，可是……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"뭐지? 갑자기 곳곳에서 침식반응이……?","JPN":"何だ？　いきなりあちこちで侵食反応が……？","ENG":"Huh? Corruption responses are emerging all over the place...?","TWN":"怎麼這樣？突然到處都有侵蝕反應……？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L11_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"침식체 활동신호가 포착됐습니다! 분류되지 않은 타입!","JPN":"侵食体の活動信号を確認しました！　未分類タイプ！","ENG":"C.O. activity detected! Type unidentified!","TWN":"發現侵蝕體蹤跡！是沒分類的類型！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"미확인이라고? 대체 어디서 문제가 발생한 건가.","JPN":"未確認だと？　いったいどこで問題が発生したんだ。","ENG":"Unidentified? What's going on?!","TWN":"沒分類？到底是從哪裡發生的？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"발생 위치는……!","JPN":"発生位置は……！","ENG":"Pinpointing location...!","TWN":"發生位置……！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"특정이 안 됩니다! 도시 전역에서 침식파가 쏟아지고 있어요!","JPN":"特定できません！　都市の全域から侵食波が溢れています！","ENG":"Unable to pinpoint location! Corruption rays are all throughout the city!","TWN":"不是特定地區！全城都受到侵蝕波影響！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"뭐? 하지만 아직 육안으로는 아무것도……","JPN":"何？　だが肉眼ではまだ何も……","ENG":"What?! But we don't see anything–","TWN":"什麼？但我現在什麼都沒看……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"침식체다! 잡아!","JPN":"侵食体だ！　捕まえろ！","ENG":"It's a C.O.! Kill it!","TWN":"是侵蝕體！攻擊！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BATTLEFIELD"},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐, 뭐였지? 어디에 있는지 안 보여……!","JPN":"な、なんだったんだ？　どこにいるのか見えない……！","ENG":"W-what? I can't see where it is...!","TWN":"什…什麼？我什麼都沒看到……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저건……?","JPN":"あれは……？","ENG":"Is that...?","TWN":"那是……？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"기척은 뚜렷하지만 눈에는 보이지 않는군요.","JPN":"気配ははっきりしていますが、目には見えませんね。","ENG":"I can feel it, but cannot see it.","TWN":"雖然可以明顯感受到動靜，肉眼卻看不到。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"제 곁에서 멀어지지 마십시오, 당주님.","JPN":"私のそばを離れないでください、当主。","ENG":"Lady Nanahara, please stay behind me.","TWN":"堂主，請不要在離我太遠的地方。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저들로부터…… 저승의 기운이 느껴져요.","JPN":"彼らから……冥府の気配が感じられます。","ENG":"I sense... the aura of the Afterlife from them.","TWN":"我從它們身上……感受到地獄的氣息。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만 이곳은 영지 밖입니다. 저승에 있어야 할 것들이 깨어났다는 건……?","JPN":"ですがここは領地の外です。冥府にいるべき者たちが目覚めたということは……？","ENG":"However, we are outside of our territory. The reason for beings of the Afterlife to awaken can only be...","TWN":"可是這裡是領地外的地方，這些原本該待在地獄的東西醒過來，就表示……？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네, 결계가 무너진 겁니다.","JPN":"はい、結界が崩れたのです。","ENG":"Yes, the barrier has fallen.","TWN":"沒錯，結界正在瓦解。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"서둘러 영지로 돌아가야겠어요.","JPN":"急いで領地に戻りましょう。","ENG":"We must hurry back home.","TWN":"必須盡快回到領地。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"인질이 타고 있던 차량이 폭발했다!","JPN":"人質が乗っていた車両が爆発した！","ENG":"The car with the hostages exploded!","TWN":"人質搭乘的車輛發生爆炸！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"컨테이너가 비어 있습니다! 폭발물을 써서 탈출한 것 같아요!","JPN":"コンテナは空っぽです！　爆発物を使って脱出したようです！","ENG":"The container is empty! They used our explosives to escape!","TWN":"裡面什是空的！看來是利用炸彈逃跑的！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"지원이 올 때까지 우선 이 괴물들부터 막아!","JPN":"支援が来るまでまずこの化け物から止めろ！","ENG":"Stop those monsters until backup arrives!","TWN":"在支援抵達前先對付這些怪物吧！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L38_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하바키가 탈출을……?","JPN":"覇吐が脱出……？","ENG":"Habaki escaped...?","TWN":"幅木逃跑……？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"아직 멀리 가지는 못했을 겁니다. 제가 놈들을 쫓겠습니다.","JPN":"まだ遠くには行っていないはずです。私がやつらを追いかけましょう。","ENG":"He could not have gone far. I will chase after him.","TWN":"他應該還沒跑遠，我去追！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"혼자서는 위험해요, 치후유.","JPN":"一人では危険です、千冬。","ENG":"It is too dangerous to go alone, Chifuyu.","TWN":"千冬，你自己一個人太危險。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만 영지에 사람들이 아직 살아 있다면, 그들을 도울 사람은 당주님뿐입니다.","JPN":"ですが領地の人たちがまた生きているなら、彼らを助けられる人は当主だけです。","ENG":"But if the residents are still alive, you are the only one who can help them, Lady Nanahara.","TWN":"但要是領地裡還有人活著，那能幫他們的就只有堂主而已。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"너무 위험을 무릅쓰진 마세요. 하바키의 행방을 알아내는 것만으로도 충분하니까요.","JPN":"あまり危険を冒さないでください。覇吐の行方を知るだけでも十分ですから。","ENG":"Promise me you will not get into too much danger. Just knowing Habaki’s location will be enough for now.","TWN":"不要太冒險，只要找到幅木的下落就好。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"명심하겠습니다.","JPN":"肝に銘じます。","ENG":"Yes, ma'am.","TWN":"是，遵命。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};